/* ══════════════════════════════════════════════════════════
   NutriAI — Custom Styles
   Light / Dark mode, animations, responsive design
═══════════════════════════════════════════════════════════ */

/* ── CSS Variables (Light Theme) ────────────────────────── */
:root {
  --bg:            #f0f4f8;
  --surface:       #ffffff;
  --surface-2:     #f7f9fc;
  --border:        #e2e8f0;
  --text:          #1a202c;
  --text-muted:    #718096;
  --primary:       #3b82f6;
  --primary-dark:  #2563eb;
  --success:       #10b981;
  --warning:       #f59e0b;
  --danger:        #ef4444;
  --purple:        #8b5cf6;
  --nav-bg:        #ffffff;
  --nav-shadow:    0 1px 3px rgba(0,0,0,.08);
  --card-shadow:   0 2px 8px rgba(0,0,0,.06);
  --card-hover:    0 6px 20px rgba(0,0,0,.10);
  --chat-user-bg:  #3b82f6;
  --chat-ai-bg:    #f0f4f8;
  --input-bg:      #ffffff;
  --footer-bg:     #1a202c;
  --footer-text:   #a0aec0;
  --transition:    0.22s cubic-bezier(.4,0,.2,1);
}

[data-theme="dark"] {
  --bg:            #0f1117;
  --surface:       #1a1d27;
  --surface-2:     #242838;
  --border:        #2d3748;
  --text:          #e2e8f0;
  --text-muted:    #a0aec0;
  --nav-bg:        #1a1d27;
  --nav-shadow:    0 1px 3px rgba(0,0,0,.4);
  --card-shadow:   0 2px 8px rgba(0,0,0,.3);
  --card-hover:    0 6px 20px rgba(0,0,0,.4);
  --chat-ai-bg:    #242838;
  --input-bg:      #242838;
}

/* ── Base ────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; }

html { scroll-behavior: smooth; }

body {
  font-family: -apple-system, "Segoe UI", system-ui, sans-serif;
  font-size: 14.5px;
  line-height: 1.65;
  background: var(--bg);
  color: var(--text);
  transition: background var(--transition), color var(--transition);
  min-height: 100vh;
}

/* ── Scrollbar ───────────────────────────────────────────── */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

/* ── Navbar ──────────────────────────────────────────────── */
#mainNav {
  background: var(--nav-bg) !important;
  box-shadow: var(--nav-shadow);
  transition: background var(--transition), box-shadow var(--transition);
  z-index: 1030;
  border-bottom: 1px solid var(--border);
}

.brand-icon {
  width: 36px; height: 36px;
  background: linear-gradient(135deg, var(--primary), var(--success));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  color: white; font-size: 18px;
  flex-shrink: 0;
}

.brand-name {
  font-weight: 700;
  font-size: 1.15rem;
  background: linear-gradient(135deg, var(--primary), var(--success));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  line-height: 1.2;
}

.brand-sub {
  font-size: 0.68rem;
  color: var(--text-muted);
  line-height: 1;
}

.nav-pill {
  border-radius: 20px !important;
  padding: 6px 14px !important;
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text-muted) !important;
  transition: all var(--transition);
}

.nav-pill:hover,
.nav-pill.active {
  background: rgba(59,130,246,.12) !important;
  color: var(--primary) !important;
}

.btn-icon {
  background: transparent;
  border: none;
  color: var(--text-muted);
  padding: 6px 8px;
  border-radius: 8px;
  font-size: 1.1rem;
  transition: all var(--transition);
}

.btn-icon:hover { background: var(--surface-2); color: var(--text); }

.status-badge {
  display: flex; align-items: center; gap: 6px;
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 20px;
  padding: 4px 12px;
  font-size: 0.78rem;
  color: var(--text-muted);
}

.status-dot {
  width: 8px; height: 8px;
  border-radius: 50%;
  background: var(--text-muted);
  animation: pulse 2s infinite;
}

.status-dot.online { background: var(--success); }
.status-dot.offline { background: var(--danger); animation: none; }

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0.4; }
}

/* ── Main Content ────────────────────────────────────────── */
.main-content { padding-bottom: 80px; }

/* ── Cards ───────────────────────────────────────────────── */
.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  box-shadow: var(--card-shadow);
  transition: box-shadow var(--transition), background var(--transition);
}

.card:hover { box-shadow: var(--card-hover); }

.card-header {
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  border-radius: 14px 14px 0 0 !important;
  padding: 14px 18px;
  color: var(--text);
  font-size: 0.9rem;
}

.card-body { padding: 18px; color: var(--text); }

/* ── Hero Banner ─────────────────────────────────────────── */
.hero-banner {
  background: linear-gradient(135deg, #1e40af 0%, #065f46 50%, #7c3aed 100%);
  border-radius: 18px;
  padding: 40px 24px;
  text-align: center;
  color: white;
  animation: fadeIn .5s ease;
  position: relative;
  overflow: hidden;
}

.hero-banner::before {
  content: '';
  position: absolute; inset: 0;
  background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.04'%3E%3Ccircle cx='30' cy='30' r='20'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
}

.hero-content { position: relative; z-index: 1; }

.hero-icon {
  font-size: 3rem; margin-bottom: 12px;
  animation: heartbeat 2s infinite;
}

@keyframes heartbeat {
  0%, 100% { transform: scale(1); }
  14% { transform: scale(1.12); }
  28% { transform: scale(1); }
  42% { transform: scale(1.06); }
  56% { transform: scale(1); }
}

.hero-title { font-size: 2.2rem; font-weight: 800; margin-bottom: 8px; }
.hero-subtitle { font-size: 1rem; opacity: .85; max-width: 600px; margin: 0 auto 16px; }

.hero-chips { display: flex; flex-wrap: wrap; gap: 8px; justify-content: center; }

.chip {
  font-size: 0.78rem; font-weight: 600;
  padding: 4px 12px; border-radius: 20px;
  opacity: .9;
}

.chip-green  { background: rgba(16,185,129,.2); border: 1px solid rgba(16,185,129,.4); }
.chip-blue   { background: rgba(59,130,246,.2); border: 1px solid rgba(59,130,246,.4); }
.chip-purple { background: rgba(139,92,246,.2); border: 1px solid rgba(139,92,246,.4); }
.chip-orange { background: rgba(245,158,11,.2); border: 1px solid rgba(245,158,11,.4); }

.btn-hero {
  background: white; color: #1e40af;
  font-weight: 700; border: none;
  padding: 10px 28px; border-radius: 24px;
  font-size: 0.95rem;
  transition: transform var(--transition), box-shadow var(--transition);
}

.btn-hero:hover { transform: translateY(-2px); box-shadow: 0 8px 20px rgba(0,0,0,.3); color: #1e40af; }

/* ── Tab Panels ──────────────────────────────────────────── */
.tab-panel { display: none; animation: fadeIn .3s ease; }
.tab-panel.active { display: block; }

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}

.section-title {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text);
}

/* ── Chat UI ─────────────────────────────────────────────── */
.card-chat {
  display: flex;
  flex-direction: column;
  min-height: 550px;
  max-height: 720px;
}

.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 14px;
  min-height: 0;
}

.chat-bubble {
  max-width: 82%;
  padding: 12px 16px;
  border-radius: 16px;
  font-size: 0.9rem;
  line-height: 1.6;
  animation: bubbleIn .25s ease;
}

@keyframes bubbleIn {
  from { opacity: 0; transform: scale(.95) translateY(6px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}

.bubble-user {
  background: var(--chat-user-bg);
  color: white;
  align-self: flex-end;
  border-bottom-right-radius: 4px;
}

.bubble-ai {
  background: var(--chat-ai-bg);
  color: var(--text);
  align-self: flex-start;
  border-bottom-left-radius: 4px;
  border: 1px solid var(--border);
}

.bubble-meta {
  font-size: 0.72rem;
  color: var(--text-muted);
  margin-top: 4px;
  text-align: right;
}

.bubble-ai .bubble-meta { text-align: left; }

.bubble-ai pre, .bubble-ai code {
  background: var(--surface-2);
  border-radius: 6px;
  font-size: 0.82rem;
  padding: 2px 6px;
  color: var(--text);
}

.bubble-ai table {
  width: 100%;
  border-collapse: collapse;
  margin: 8px 0;
  font-size: 0.83rem;
}

.bubble-ai th, .bubble-ai td {
  border: 1px solid var(--border);
  padding: 6px 10px;
  text-align: left;
}

.bubble-ai th { background: var(--surface-2); font-weight: 600; }

.avatar-ai {
  width: 32px; height: 32px;
  background: linear-gradient(135deg, var(--primary), var(--success));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  color: white; font-size: 15px;
  flex-shrink: 0;
}

.typing-indicator {
  display: flex; align-items: center; gap: 4px;
  padding: 10px 14px;
}

.typing-dot {
  width: 7px; height: 7px;
  border-radius: 50%;
  background: var(--text-muted);
  animation: typing 1.2s infinite;
}

.typing-dot:nth-child(2) { animation-delay: .2s; }
.typing-dot:nth-child(3) { animation-delay: .4s; }

@keyframes typing {
  0%, 80%, 100% { transform: scale(1); opacity: .6; }
  40%            { transform: scale(1.3); opacity: 1; }
}

/* Quick Prompts */
.quick-prompts {
  padding: 10px 14px;
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  border-top: 1px solid var(--border);
}

.qp-btn {
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 5px 12px;
  font-size: 0.78rem;
  color: var(--text);
  cursor: pointer;
  transition: all var(--transition);
  white-space: nowrap;
}

.qp-btn:hover {
  background: rgba(59,130,246,.1);
  border-color: var(--primary);
  color: var(--primary);
  transform: translateY(-1px);
}

/* Chat Input */
.chat-input-bar {
  display: flex;
  align-items: flex-end;
  gap: 10px;
  padding: 12px 16px;
  border-top: 1px solid var(--border);
  background: var(--surface);
}

.chat-textarea {
  flex: 1;
  background: var(--input-bg);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 10px 14px;
  resize: none;
  font-size: 0.9rem;
  color: var(--text);
  transition: border var(--transition);
  max-height: 120px;
  overflow-y: auto;
}

.chat-textarea:focus {
  outline: none;
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(59,130,246,.15);
}

.btn-send {
  width: 42px; height: 42px;
  background: var(--primary);
  border: none;
  border-radius: 12px;
  color: white;
  font-size: 1.1rem;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
  transition: all var(--transition);
}

.btn-send:hover { background: var(--primary-dark); transform: translateY(-1px); }

/* ── Stat Cards ──────────────────────────────────────────── */
.stat-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 20px 16px;
  text-align: center;
  box-shadow: var(--card-shadow);
  transition: all var(--transition);
  position: relative;
  overflow: hidden;
}

.stat-card:hover { transform: translateY(-3px); box-shadow: var(--card-hover); }

.stat-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 3px;
}

.stat-calories::before  { background: linear-gradient(90deg, #f97316, #ef4444); }
.stat-protein::before   { background: linear-gradient(90deg, #3b82f6, #6366f1); }
.stat-carbs::before     { background: linear-gradient(90deg, #f59e0b, #f97316); }
.stat-fat::before       { background: linear-gradient(90deg, #10b981, #059669); }

.stat-icon {
  font-size: 1.8rem;
  margin-bottom: 6px;
}

.stat-calories .stat-icon  { color: #f97316; }
.stat-protein .stat-icon   { color: #3b82f6; }
.stat-carbs .stat-icon     { color: #f59e0b; }
.stat-fat .stat-icon       { color: #10b981; }

.stat-value {
  font-size: 1.7rem;
  font-weight: 800;
  color: var(--text);
  line-height: 1.1;
}

.stat-label { font-size: 0.82rem; font-weight: 600; color: var(--text); margin-top: 2px; }
.stat-sub   { font-size: 0.72rem; color: var(--text-muted); }

/* ── Macro Chart ─────────────────────────────────────────── */
.macro-chart { display: flex; flex-direction: column; gap: 10px; }

.macro-bar-row {
  display: flex; align-items: center; gap: 10px;
}

.macro-label { width: 70px; font-size: 0.82rem; font-weight: 500; color: var(--text-muted); }

.macro-bar-bg {
  flex: 1; height: 10px;
  background: var(--surface-2);
  border-radius: 5px;
  overflow: hidden;
}

.macro-bar {
  height: 100%;
  border-radius: 5px;
  transition: width .6s cubic-bezier(.4,0,.2,1);
}

.macro-protein { background: linear-gradient(90deg, #3b82f6, #6366f1); }
.macro-carbs   { background: linear-gradient(90deg, #f59e0b, #f97316); }
.macro-fats    { background: linear-gradient(90deg, #10b981, #059669); }
.macro-pct     { width: 36px; font-size: 0.78rem; font-weight: 600; color: var(--text-muted); text-align: right; }

/* Mini stats */
.mini-stat { padding: 8px 4px; }
.mini-val  { font-size: 1.1rem; font-weight: 700; color: var(--text); line-height: 1.2; }
.mini-lbl  { font-size: 0.72rem; color: var(--text-muted); }

/* ── BMI Calculator ──────────────────────────────────────── */
.bmi-gauge-wrap { padding: 10px 0; }

.bmi-number {
  font-size: 4rem;
  font-weight: 900;
  line-height: 1;
  background: linear-gradient(135deg, var(--primary), var(--success));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.bmi-category {
  font-size: 1rem;
  padding: 5px 16px;
  border-radius: 20px;
}

.bmi-scale { position: relative; padding-bottom: 24px; }

.bmi-scale-bar {
  display: flex;
  height: 14px;
  border-radius: 7px;
  overflow: hidden;
  margin-bottom: 6px;
}

.bmi-segment { flex: 1; }
.seg-under  { background: #60a5fa; }
.seg-normal { background: #10b981; }
.seg-over   { background: #f59e0b; }
.seg-obese  { background: #ef4444; }

.bmi-scale-labels {
  display: flex;
  justify-content: space-between;
  font-size: 0.72rem;
  color: var(--text-muted);
  padding: 0 25%;
}

.bmi-indicator {
  position: absolute;
  bottom: 0;
  transform: translateX(-50%);
  font-size: 0.85rem;
  color: var(--text);
  transition: left .8s cubic-bezier(.4,0,.2,1);
}

/* Result chips */
.result-chip {
  border-radius: 12px;
  padding: 10px 8px;
  text-align: center;
  border: 1px solid var(--border);
}

.rc-label { font-size: 0.7rem; font-weight: 600; text-transform: uppercase; letter-spacing: .5px; color: var(--text-muted); margin-bottom: 2px; }
.rc-val   { font-size: 1.3rem; font-weight: 800; line-height: 1; }
.rc-sub   { font-size: 0.68rem; color: var(--text-muted); }

.chip-blue   .rc-val { color: #3b82f6; }
.chip-green  .rc-val { color: #10b981; }
.chip-orange .rc-val { color: #f59e0b; }
.chip-purple .rc-val { color: #8b5cf6; }

/* Macro targets */
.macro-targets { border-top: 1px solid var(--border); padding-top: 12px; display: flex; flex-direction: column; gap: 6px; }

.macro-target-item {
  display: flex;
  justify-content: space-between;
  font-size: 0.85rem;
  color: var(--text-muted);
  padding: 4px 0;
  border-bottom: 1px dashed var(--border);
}

.macro-target-item strong { color: var(--text); }

/* ── Family Members ──────────────────────────────────────── */
.family-member-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 8px 12px;
  margin-bottom: 8px;
  font-size: 0.85rem;
  animation: fadeIn .2s ease;
}

.fm-name { font-weight: 600; color: var(--text); }
.fm-meta { color: var(--text-muted); font-size: 0.78rem; }

.fm-remove {
  background: none;
  border: none;
  color: var(--danger);
  cursor: pointer;
  font-size: 1rem;
  padding: 2px 6px;
  border-radius: 6px;
  transition: background var(--transition);
}

.fm-remove:hover { background: rgba(239,68,68,.1); }

/* ── Superfoods Grid ─────────────────────────────────────── */
.superfood-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 16px;
  text-align: center;
  transition: all var(--transition);
  cursor: default;
}

.superfood-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--card-hover);
  border-color: var(--primary);
}

.sf-emoji { font-size: 2.2rem; margin-bottom: 8px; }
.sf-name  { font-weight: 700; font-size: 0.88rem; color: var(--text); }
.sf-hindi { font-size: 0.75rem; color: var(--text-muted); }

/* ── AI Response Box ─────────────────────────────────────── */
.ai-response-box {
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 18px;
  font-size: 0.88rem;
  line-height: 1.8;
  color: var(--text);
  white-space: pre-wrap;
  word-break: break-word;
}

.ai-response-box h1, .ai-response-box h2 {
  font-size: 1rem; font-weight: 700; margin: 12px 0 6px; color: var(--text);
}

.ai-response-box h3, .ai-response-box h4 {
  font-size: 0.92rem; font-weight: 700; margin: 10px 0 4px; color: var(--primary);
}

.ai-response-box ul, .ai-response-box ol {
  padding-left: 18px;
}

.ai-response-box table {
  width: 100%; border-collapse: collapse; margin: 8px 0; font-size: 0.82rem;
}

.ai-response-box th, .ai-response-box td {
  border: 1px solid var(--border); padding: 6px 10px; text-align: left;
}

.ai-response-box th { background: var(--surface); font-weight: 600; }
.ai-response-box strong { color: var(--text); }
.ai-response-box em { color: var(--text-muted); }
.ai-response-box hr { border-color: var(--border); margin: 10px 0; }

/* ── Tip Card ────────────────────────────────────────────── */
.card-tip {
  background: linear-gradient(135deg, rgba(59,130,246,.08), rgba(16,185,129,.08));
  border: 1px solid rgba(59,130,246,.2);
}

.tip-header { font-size: 0.82rem; margin-bottom: 6px; }
.tip-text   { font-size: 0.82rem; color: var(--text-muted); }

/* ── Forms ───────────────────────────────────────────────── */
.form-control, .form-select {
  background: var(--input-bg);
  border-color: var(--border);
  color: var(--text);
  font-size: 0.88rem;
  border-radius: 8px;
  transition: border var(--transition), background var(--transition);
}

.form-control:focus, .form-select:focus {
  background: var(--input-bg);
  border-color: var(--primary);
  color: var(--text);
  box-shadow: 0 0 0 3px rgba(59,130,246,.15);
}

.form-label { color: var(--text); font-size: 0.82rem; margin-bottom: 4px; }

/* ── Buttons ─────────────────────────────────────────────── */
.btn-primary {
  background: var(--primary);
  border-color: var(--primary);
  font-weight: 600;
  border-radius: 10px;
  transition: all var(--transition);
}

.btn-primary:hover {
  background: var(--primary-dark);
  border-color: var(--primary-dark);
  transform: translateY(-1px);
}

.btn-outline-primary { border-color: var(--primary); color: var(--primary); border-radius: 10px; font-weight: 600; }
.btn-outline-primary:hover { background: var(--primary); }
.btn-outline-secondary { border-color: var(--border); color: var(--text-muted); border-radius: 8px; }

/* ── Footer ──────────────────────────────────────────────── */
.app-footer {
  background: var(--nav-bg);
  border-top: 1px solid var(--border);
  position: fixed;
  bottom: 0; left: 0; right: 0;
  z-index: 100;
}

.footer-brand { font-weight: 700; font-size: 0.9rem; color: var(--text); }

/* ── Toast ───────────────────────────────────────────────── */
.toast {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: 12px;
  font-size: 0.85rem;
}

/* ── Utilities ───────────────────────────────────────────── */
.text-primary { color: var(--primary) !important; }
.text-success { color: var(--success) !important; }
.text-warning { color: var(--warning) !important; }
.text-danger  { color: var(--danger) !important; }
.text-muted   { color: var(--text-muted) !important; }

/* ── Responsive ──────────────────────────────────────────── */
@media (max-width: 576px) {
  .hero-title   { font-size: 1.5rem; }
  .hero-banner  { padding: 28px 16px; }
  .stat-value   { font-size: 1.3rem; }
  .bmi-number   { font-size: 3rem; }
  .quick-prompts { display: none; }
  .card-chat    { min-height: 460px; }
}

@media (max-width: 768px) {
  .hero-chips { gap: 6px; }
  .tab-panel.active { animation: none; }
}

/* ── Print ───────────────────────────────────────────────── */
@media print {
  #mainNav, .app-footer, .quick-prompts, .chat-input-bar, #heroBanner { display: none !important; }
  .card { box-shadow: none !important; border: 1px solid #e0e0e0 !important; }
  body { background: white !important; color: black !important; }
}

/* ══════════════════════════════════════════════════════════
   NutriAI — Custom Styles
   Light / Dark mode, animations, responsive design
═══════════════════════════════════════════════════════════ */

/* ── CSS Variables (Light Theme) ────────────────────────── */
:root {
  --bg:            #f0f4f8;
  --surface:       #ffffff;
  --surface-2:     #f7f9fc;
  --border:        #e2e8f0;
  --text:          #1a202c;
  --text-muted:    #718096;
  --primary:       #3b82f6;
  --primary-dark:  #2563eb;
  --success:       #10b981;
  --warning:       #f59e0b;
  --danger:        #ef4444;
  --purple:        #8b5cf6;
  --nav-bg:        #ffffff;
  --nav-shadow:    0 1px 3px rgba(0,0,0,.08);
  --card-shadow:   0 2px 8px rgba(0,0,0,.06);
  --card-hover:    0 6px 20px rgba(0,0,0,.10);
  --chat-user-bg:  #3b82f6;
  --chat-ai-bg:    #f0f4f8;
  --input-bg:      #ffffff;
  --footer-bg:     #1a202c;
  --footer-text:   #a0aec0;
  --transition:    0.22s cubic-bezier(.4,0,.2,1);
}

[data-theme="dark"] {
  --bg:            #0f1117;
  --surface:       #1a1d27;
  --surface-2:     #242838;
  --border:        #2d3748;
  --text:          #e2e8f0;
  --text-muted:    #a0aec0;
  --nav-bg:        #1a1d27;
  --nav-shadow:    0 1px 3px rgba(0,0,0,.4);
  --card-shadow:   0 2px 8px rgba(0,0,0,.3);
  --card-hover:    0 6px 20px rgba(0,0,0,.4);
  --chat-ai-bg:    #242838;
  --input-bg:      #242838;
}

/* ── Base ────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; }

html { scroll-behavior: smooth; }

body {
  font-family: -apple-system, "Segoe UI", system-ui, sans-serif;
  font-size: 14.5px;
  line-height: 1.65;
  background: var(--bg);
  color: var(--text);
  transition: background var(--transition), color var(--transition);
  min-height: 100vh;
}

/* ── Scrollbar ───────────────────────────────────────────── */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

/* ── Navbar ──────────────────────────────────────────────── */
#mainNav {
  background: var(--nav-bg) !important;
  box-shadow: var(--nav-shadow);
  transition: background var(--transition), box-shadow var(--transition);
  z-index: 1030;
  border-bottom: 1px solid var(--border);
}

.brand-icon {
  width: 36px; height: 36px;
  background: linear-gradient(135deg, var(--primary), var(--success));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  color: white; font-size: 18px;
  flex-shrink: 0;
}

.brand-name {
  font-weight: 700;
  font-size: 1.15rem;
  background: linear-gradient(135deg, var(--primary), var(--success));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  line-height: 1.2;
}

.brand-sub {
  font-size: 0.68rem;
  color: var(--text-muted);
  line-height: 1;
}

.nav-pill {
  border-radius: 20px !important;
  padding: 6px 14px !important;
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text-muted) !important;
  transition: all var(--transition);
}

.nav-pill:hover,
.nav-pill.active {
  background: rgba(59,130,246,.12) !important;
  color: var(--primary) !important;
}

.btn-icon {
  background: transparent;
  border: none;
  color: var(--text-muted);
  padding: 6px 8px;
  border-radius: 8px;
  font-size: 1.1rem;
  transition: all var(--transition);
}

.btn-icon:hover { background: var(--surface-2); color: var(--text); }

.status-badge {
  display: flex; align-items: center; gap: 6px;
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 20px;
  padding: 4px 12px;
  font-size: 0.78rem;
  color: var(--text-muted);
}

.status-dot {
  width: 8px; height: 8px;
  border-radius: 50%;
  background: var(--text-muted);
  animation: pulse 2s infinite;
}

.status-dot.online { background: var(--success); }
.status-dot.offline { background: var(--danger); animation: none; }

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0.4; }
}

/* ── Main Content ────────────────────────────────────────── */
.main-content { padding-bottom: 80px; }

/* ── Cards ───────────────────────────────────────────────── */
.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  box-shadow: var(--card-shadow);
  transition: box-shadow var(--transition), background var(--transition);
}

.card:hover { box-shadow: var(--card-hover); }

.card-header {
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  border-radius: 14px 14px 0 0 !important;
  padding: 14px 18px;
  color: var(--text);
  font-size: 0.9rem;
}

.card-body { padding: 18px; color: var(--text); }

/* ── Hero Banner ─────────────────────────────────────────── */
.hero-banner {
  background: linear-gradient(135deg, #1e40af 0%, #065f46 50%, #7c3aed 100%);
  border-radius: 18px;
  padding: 40px 24px;
  text-align: center;
  color: white;
  animation: fadeIn .5s ease;
  position: relative;
  overflow: hidden;
}

.hero-banner::before {
  content: '';
  position: absolute; inset: 0;
  background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.04'%3E%3Ccircle cx='30' cy='30' r='20'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
}

.hero-content { position: relative; z-index: 1; }

.hero-icon {
  font-size: 3rem; margin-bottom: 12px;
  animation: heartbeat 2s infinite;
}

@keyframes heartbeat {
  0%, 100% { transform: scale(1); }
  14% { transform: scale(1.12); }
  28% { transform: scale(1); }
  42% { transform: scale(1.06); }
  56% { transform: scale(1); }
}

.hero-title { font-size: 2.2rem; font-weight: 800; margin-bottom: 8px; }
.hero-subtitle { font-size: 1rem; opacity: .85; max-width: 600px; margin: 0 auto 16px; }

.hero-chips { display: flex; flex-wrap: wrap; gap: 8px; justify-content: center; }

.chip {
  font-size: 0.78rem; font-weight: 600;
  padding: 4px 12px; border-radius: 20px;
  opacity: .9;
}

.chip-green  { background: rgba(16,185,129,.2); border: 1px solid rgba(16,185,129,.4); }
.chip-blue   { background: rgba(59,130,246,.2); border: 1px solid rgba(59,130,246,.4); }
.chip-purple { background: rgba(139,92,246,.2); border: 1px solid rgba(139,92,246,.4); }
.chip-orange { background: rgba(245,158,11,.2); border: 1px solid rgba(245,158,11,.4); }

.btn-hero {
  background: white; color: #1e40af;
  font-weight: 700; border: none;
  padding: 10px 28px; border-radius: 24px;
  font-size: 0.95rem;
  transition: transform var(--transition), box-shadow var(--transition);
}

.btn-hero:hover { transform: translateY(-2px); box-shadow: 0 8px 20px rgba(0,0,0,.3); color: #1e40af; }

/* ── Tab Panels ──────────────────────────────────────────── */
.tab-panel { display: none; animation: fadeIn .3s ease; }
.tab-panel.active { display: block; }

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}

.section-title {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text);
}

/* ── Chat UI ─────────────────────────────────────────────── */
.card-chat {
  display: flex;
  flex-direction: column;
  min-height: 550px;
  max-height: 720px;
}

.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 14px;
  min-height: 0;
}

.chat-bubble {
  max-width: 82%;
  padding: 12px 16px;
  border-radius: 16px;
  font-size: 0.9rem;
  line-height: 1.6;
  animation: bubbleIn .25s ease;
}

@keyframes bubbleIn {
  from { opacity: 0; transform: scale(.95) translateY(6px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}

.bubble-user {
  background: var(--chat-user-bg);
  color: white;
  align-self: flex-end;
  border-bottom-right-radius: 4px;
}

.bubble-ai {
  background: var(--chat-ai-bg);
  color: var(--text);
  align-self: flex-start;
  border-bottom-left-radius: 4px;
  border: 1px solid var(--border);
}

.bubble-meta {
  font-size: 0.72rem;
  color: var(--text-muted);
  margin-top: 4px;
  text-align: right;
}

.bubble-ai .bubble-meta { text-align: left; }

.bubble-ai pre, .bubble-ai code {
  background: var(--surface-2);
  border-radius: 6px;
  font-size: 0.82rem;
  padding: 2px 6px;
  color: var(--text);
}

.bubble-ai table {
  width: 100%;
  border-collapse: collapse;
  margin: 8px 0;
  font-size: 0.83rem;
}

.bubble-ai th, .bubble-ai td {
  border: 1px solid var(--border);
  padding: 6px 10px;
  text-align: left;
}

.bubble-ai th { background: var(--surface-2); font-weight: 600; }

.avatar-ai {
  width: 32px; height: 32px;
  background: linear-gradient(135deg, var(--primary), var(--success));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  color: white; font-size: 15px;
  flex-shrink: 0;
}

.typing-indicator {
  display: flex; align-items: center; gap: 4px;
  padding: 10px 14px;
}

.typing-dot {
  width: 7px; height: 7px;
  border-radius: 50%;
  background: var(--text-muted);
  animation: typing 1.2s infinite;
}

.typing-dot:nth-child(2) { animation-delay: .2s; }
.typing-dot:nth-child(3) { animation-delay: .4s; }

@keyframes typing {
  0%, 80%, 100% { transform: scale(1); opacity: .6; }
  40%            { transform: scale(1.3); opacity: 1; }
}

/* Quick Prompts */
.quick-prompts {
  padding: 10px 14px;
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  border-top: 1px solid var(--border);
}

.qp-btn {
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 5px 12px;
  font-size: 0.78rem;
  color: var(--text);
  cursor: pointer;
  transition: all var(--transition);
  white-space: nowrap;
}

.qp-btn:hover {
  background: rgba(59,130,246,.1);
  border-color: var(--primary);
  color: var(--primary);
  transform: translateY(-1px);
}

/* Chat Input */
.chat-input-bar {
  display: flex;
  align-items: flex-end;
  gap: 10px;
  padding: 12px 16px;
  border-top: 1px solid var(--border);
  background: var(--surface);
}

.chat-textarea {
  flex: 1;
  background: var(--input-bg);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 10px 14px;
  resize: none;
  font-size: 0.9rem;
  color: var(--text);
  transition: border var(--transition);
  max-height: 120px;
  overflow-y: auto;
}

.chat-textarea:focus {
  outline: none;
  border-color: var(--primary);
  box-shadow: 0 0 0 3px rgba(59,130,246,.15);
}

.btn-send {
  width: 42px; height: 42px;
  background: var(--primary);
  border: none;
  border-radius: 12px;
  color: white;
  font-size: 1.1rem;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
  transition: all var(--transition);
}

.btn-send:hover { background: var(--primary-dark); transform: translateY(-1px); }

/* ── Stat Cards ──────────────────────────────────────────── */
.stat-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 20px 16px;
  text-align: center;
  box-shadow: var(--card-shadow);
  transition: all var(--transition);
  position: relative;
  overflow: hidden;
}

.stat-card:hover { transform: translateY(-3px); box-shadow: var(--card-hover); }

.stat-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 3px;
}

.stat-calories::before  { background: linear-gradient(90deg, #f97316, #ef4444); }
.stat-protein::before   { background: linear-gradient(90deg, #3b82f6, #6366f1); }
.stat-carbs::before     { background: linear-gradient(90deg, #f59e0b, #f97316); }
.stat-fat::before       { background: linear-gradient(90deg, #10b981, #059669); }

.stat-icon {
  font-size: 1.8rem;
  margin-bottom: 6px;
}

.stat-calories .stat-icon  { color: #f97316; }
.stat-protein .stat-icon   { color: #3b82f6; }
.stat-carbs .stat-icon     { color: #f59e0b; }
.stat-fat .stat-icon       { color: #10b981; }

.stat-value {
  font-size: 1.7rem;
  font-weight: 800;
  color: var(--text);
  line-height: 1.1;
}

.stat-label { font-size: 0.82rem; font-weight: 600; color: var(--text); margin-top: 2px; }
.stat-sub   { font-size: 0.72rem; color: var(--text-muted); }

/* ── Macro Chart ─────────────────────────────────────────── */
.macro-chart { display: flex; flex-direction: column; gap: 10px; }

.macro-bar-row {
  display: flex; align-items: center; gap: 10px;
}

.macro-label { width: 70px; font-size: 0.82rem; font-weight: 500; color: var(--text-muted); }

.macro-bar-bg {
  flex: 1; height: 10px;
  background: var(--surface-2);
  border-radius: 5px;
  overflow: hidden;
}

.macro-bar {
  height: 100%;
  border-radius: 5px;
  transition: width .6s cubic-bezier(.4,0,.2,1);
}

.macro-protein { background: linear-gradient(90deg, #3b82f6, #6366f1); }
.macro-carbs   { background: linear-gradient(90deg, #f59e0b, #f97316); }
.macro-fats    { background: linear-gradient(90deg, #10b981, #059669); }
.macro-pct     { width: 36px; font-size: 0.78rem; font-weight: 600; color: var(--text-muted); text-align: right; }

/* Mini stats */
.mini-stat { padding: 8px 4px; }
.mini-val  { font-size: 1.1rem; font-weight: 700; color: var(--text); line-height: 1.2; }
.mini-lbl  { font-size: 0.72rem; color: var(--text-muted); }

/* ── BMI Calculator ──────────────────────────────────────── */
.bmi-gauge-wrap { padding: 10px 0; }

.bmi-number {
  font-size: 4rem;
  font-weight: 900;
  line-height: 1;
  background: linear-gradient(135deg, var(--primary), var(--success));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.bmi-category {
  font-size: 1rem;
  padding: 5px 16px;
  border-radius: 20px;
}

.bmi-scale { position: relative; padding-bottom: 24px; }

.bmi-scale-bar {
  display: flex;
  height: 14px;
  border-radius: 7px;
  overflow: hidden;
  margin-bottom: 6px;
}

.bmi-segment { flex: 1; }
.seg-under  { background: #60a5fa; }
.seg-normal { background: #10b981; }
.seg-over   { background: #f59e0b; }
.seg-obese  { background: #ef4444; }

.bmi-scale-labels {
  display: flex;
  justify-content: space-between;
  font-size: 0.72rem;
  color: var(--text-muted);
  padding: 0 25%;
}

.bmi-indicator {
  position: absolute;
  bottom: 0;
  transform: translateX(-50%);
  font-size: 0.85rem;
  color: var(--text);
  transition: left .8s cubic-bezier(.4,0,.2,1);
}

/* Result chips */
.result-chip {
  border-radius: 12px;
  padding: 10px 8px;
  text-align: center;
  border: 1px solid var(--border);
}

.rc-label { font-size: 0.7rem; font-weight: 600; text-transform: uppercase; letter-spacing: .5px; color: var(--text-muted); margin-bottom: 2px; }
.rc-val   { font-size: 1.3rem; font-weight: 800; line-height: 1; }
.rc-sub   { font-size: 0.68rem; color: var(--text-muted); }

.chip-blue   .rc-val { color: #3b82f6; }
.chip-green  .rc-val { color: #10b981; }
.chip-orange .rc-val { color: #f59e0b; }
.chip-purple .rc-val { color: #8b5cf6; }

/* Macro targets */
.macro-targets { border-top: 1px solid var(--border); padding-top: 12px; display: flex; flex-direction: column; gap: 6px; }

.macro-target-item {
  display: flex;
  justify-content: space-between;
  font-size: 0.85rem;
  color: var(--text-muted);
  padding: 4px 0;
  border-bottom: 1px dashed var(--border);
}

.macro-target-item strong { color: var(--text); }

/* ── Family Members ──────────────────────────────────────── */
.family-member-card {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 8px 12px;
  margin-bottom: 8px;
  font-size: 0.85rem;
  animation: fadeIn .2s ease;
}

.fm-name { font-weight: 600; color: var(--text); }
.fm-meta { color: var(--text-muted); font-size: 0.78rem; }

.fm-remove {
  background: none;
  border: none;
  color: var(--danger);
  cursor: pointer;
  font-size: 1rem;
  padding: 2px 6px;
  border-radius: 6px;
  transition: background var(--transition);
}

.fm-remove:hover { background: rgba(239,68,68,.1); }

/* ── Superfoods Grid ─────────────────────────────────────── */
.superfood-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 16px;
  text-align: center;
  transition: all var(--transition);
  cursor: default;
}

.superfood-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--card-hover);
  border-color: var(--primary);
}

.sf-emoji { font-size: 2.2rem; margin-bottom: 8px; }
.sf-name  { font-weight: 700; font-size: 0.88rem; color: var(--text); }
.sf-hindi { font-size: 0.75rem; color: var(--text-muted); }

/* ── AI Response Box ─────────────────────────────────────── */
.ai-response-box {
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 18px;
  font-size: 0.88rem;
  line-height: 1.8;
  color: var(--text);
  white-space: pre-wrap;
  word-break: break-word;
}

.ai-response-box h1, .ai-response-box h2 {
  font-size: 1rem; font-weight: 700; margin: 12px 0 6px; color: var(--text);
}

.ai-response-box h3, .ai-response-box h4 {
  font-size: 0.92rem; font-weight: 700; margin: 10px 0 4px; color: var(--primary);
}

.ai-response-box ul, .ai-response-box ol {
  padding-left: 18px;
}

.ai-response-box table {
  width: 100%; border-collapse: collapse; margin: 8px 0; font-size: 0.82rem;
}

.ai-response-box th, .ai-response-box td {
  border: 1px solid var(--border); padding: 6px 10px; text-align: left;
}

.ai-response-box th { background: var(--surface); font-weight: 600; }
.ai-response-box strong { color: var(--text); }
.ai-response-box em { color: var(--text-muted); }
.ai-response-box hr { border-color: var(--border); margin: 10px 0; }

/* ── Tip Card ────────────────────────────────────────────── */
.card-tip {
  background: linear-gradient(135deg, rgba(59,130,246,.08), rgba(16,185,129,.08));
  border: 1px solid rgba(59,130,246,.2);
}

.tip-header { font-size: 0.82rem; margin-bottom: 6px; }
.tip-text   { font-size: 0.82rem; color: var(--text-muted); }

/* ── Forms ───────────────────────────────────────────────── */
.form-control, .form-select {
  background: var(--input-bg);
  border-color: var(--border);
  color: var(--text);
  font-size: 0.88rem;
  border-radius: 8px;
  transition: border var(--transition), background var(--transition);
}

.form-control:focus, .form-select:focus {
  background: var(--input-bg);
  border-color: var(--primary);
  color: var(--text);
  box-shadow: 0 0 0 3px rgba(59,130,246,.15);
}

.form-label { color: var(--text); font-size: 0.82rem; margin-bottom: 4px; }

/* ── Buttons ─────────────────────────────────────────────── */
.btn-primary {
  background: var(--primary);
  border-color: var(--primary);
  font-weight: 600;
  border-radius: 10px;
  transition: all var(--transition);
}

.btn-primary:hover {
