/* ── Tip Card ────────────────────────────────────────────── */
.card-tip {
  background: linear-gradient(135deg, rgba(59,130,246,.08), rgba(16,185,129,.08));
  border: 1px solid rgba(59,130,246,.2);
}

.tip-header { font-size: 0.82rem; margin-bottom: 6px; }
.tip-text   { font-size: 0.82rem; color: var(--text-muted); }

/* ── Forms ───────────────────────────────────────────────── */
.form-control, .form-select {
  background: var(--input-bg);
  border-color: var(--border);
  color: var(--text);
  font-size: 0.88rem;
  border-radius: 8px;
  transition: border var(--transition), background var(--transition);
}

.form-control:focus, .form-select:focus {
  background: var(--input-bg);
  border-color: var(--primary);
  color: var(--text);
  box-shadow: 0 0 0 3px rgba(59,130,246,.15);
}

.form-label { color: var(--text); font-size: 0.82rem; margin-bottom: 4px; }

/* ── Buttons ─────────────────────────────────────────────── */
.btn-primary {
  background: var(--primary);
  border-color: var(--primary);
  font-weight: 600;
  border-radius: 10px;
  transition: all var(--transition);
}

.btn-primary:hover {
  background: var(--primary-dark);
  border-color: var(--primary-dark);
  transform: translateY(-1px);
}

.btn-outline-primary { border-color: var(--primary); color: var(--primary); border-radius: 10px; font-weight: 600; }
.btn-outline-primary:hover { background: var(--primary); }
.btn-outline-secondary { border-color: var(--border); color: var(--text-muted); border-radius: 8px; }

/* ── Footer ──────────────────────────────────────────────── */
.app-footer {
  background: var(--nav-bg);
  border-top: 1px solid var(--border);
  position: fixed;
  bottom: 0; left: 0; right: 0;
  z-index: 100;
}

.footer-brand { font-weight: 700; font-size: 0.9rem; color: var(--text); }

/* ── Toast ───────────────────────────────────────────────── */
.toast {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: 12px;
  font-size: 0.85rem;
}

/* ── Utilities ───────────────────────────────────────────── */
.text-primary { color: var(--primary) !important; }
.text-success { color: var(--success) !important; }
.text-warning { color: var(--warning) !important; }
.text-danger  { color: var(--danger) !important; }
.text-muted   { color: var(--text-muted) !important; }

/* ── Responsive ──────────────────────────────────────────── */
@media (max-width: 576px) {
  .hero-title   { font-size: 1.5rem; }
  .hero-banner  { padding: 28px 16px; }
  .stat-value   { font-size: 1.3rem; }
  .bmi-number   { font-size: 3rem; }
  .quick-prompts { display: none; }
  .card-chat    { min-height: 460px; }
}

@media (max-width: 768px) {
  .hero-chips { gap: 6px; }
  .tab-panel.active { animation: none; }
}

/* ── Print ───────────────────────────────────────────────── */
@media print {
  #mainNav, .app-footer, .quick-prompts, .chat-input-bar, #heroBanner { display: none !important; }
  .card { box-shadow: none !important; border: 1px solid #e0e0e0 !important; }
  body { background: white !important; color: black !important; }
}

