/* ════════════════════════════════════════════════════
   NutriAI — Full Application Styles
   Light / Dark mode · Animations · Responsive
════════════════════════════════════════════════════ */

/* ── CSS Variables ──────────────────────────────── */
:root {
  --bg:          #f2f6fb;
  --surface:     #ffffff;
  --surface-2:   #f7f9fd;
  --border:      #e2e8f0;
  --text:        #1a202c;
  --text-2:      #4a5568;
  --text-muted:  #718096;
  --c-accent:    #3b82f6;
  --c-accent-d:  #2563eb;
  --c-green:     #10b981;
  --c-orange:    #f59e0b;
  --c-purple:    #8b5cf6;
  --c-red:       #ef4444;
  --c-green-soft:#d1fae5;
  --c-blue-soft: #dbeafe;
  --c-orange-soft:#fef3c7;
  --c-purple-soft:#ede9fe;
  --nav-bg:      #ffffff;
  --shadow-sm:   0 1px 3px rgba(0,0,0,.07);
  --shadow-md:   0 4px 12px rgba(0,0,0,.09);
  --shadow-lg:   0 8px 24px rgba(0,0,0,.12);
  --radius:      14px;
  --radius-sm:   8px;
  --transition:  .2s cubic-bezier(.4,0,.2,1);
}

[data-theme="dark"] {
  --bg:          #0d1117;
  --surface:     #161b22;
  --surface-2:   #21262d;
  --border:      #30363d;
  --text:        #e6edf3;
  --text-2:      #b1bac4;
  --text-muted:  #8b949e;
  --nav-bg:      #161b22;
  --c-green-soft:#0e3d2b;
  --c-blue-soft: #102d56;
  --c-orange-soft:#3d2a00;
  --c-purple-soft:#2d1e56;
  --shadow-sm:   0 1px 3px rgba(0,0,0,.3);
  --shadow-md:   0 4px 12px rgba(0,0,0,.4);
  --shadow-lg:   0 8px 24px rgba(0,0,0,.5);
}

/* ── Reset & Base ───────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { scroll-behavior: smooth; }

body {
  font-family: -apple-system, "Segoe UI", system-ui, sans-serif;
  font-size: 14.5px;
  line-height: 1.65;
  background: var(--bg);
  color: var(--text);
  transition: background var(--transition), color var(--transition);
}

::-webkit-scrollbar        { width: 5px; height: 5px; }
::-webkit-scrollbar-track  { background: transparent; }
::-webkit-scrollbar-thumb  { background: var(--border); border-radius: 3px; }

/* ── Navbar ─────────────────────────────────────── */
#mainNav {
  background: var(--nav-bg) !important;
  border-bottom: 1px solid var(--border);
  box-shadow: var(--shadow-sm);
  padding: 8px 0;
}

.brand-icon { font-size: 1.5rem; line-height: 1; }
.brand-text {
  font-weight: 800;
  font-size: 1.1rem;
  background: linear-gradient(135deg, var(--c-accent), var(--c-green));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.nav-btn {
  background: transparent;
  border: 1px solid var(--border);
  color: var(--text-muted);
  border-radius: var(--radius-sm);
  padding: 5px 9px;
  transition: all var(--transition);
}
.nav-btn:hover { background: var(--surface-2); color: var(--text); }

.navbar-nav .nav-link {
  color: var(--text-2) !important;
  font-size: 0.87rem;
  font-weight: 500;
  border-radius: 20px;
  padding: 5px 12px !important;
  transition: all var(--transition);
}
.navbar-nav .nav-link:hover,
.navbar-nav .nav-link.active {
  background: rgba(59,130,246,.1);
  color: var(--c-accent) !important;
}

/* ── Hero Banner ────────────────────────────────── */
.hero-banner {
  background: linear-gradient(135deg, #1e3a5f 0%, #0d4d2f 60%, #4c1d95 100%);
  color: white;
  padding: 52px 24px 40px;
  position: relative;
  overflow: hidden;
  display: grid;
  grid-template-columns: 1fr auto;
  gap: 24px;
  align-items: center;
}

.hero-banner::before {
  content: '';
  position: absolute; inset: 0;
  background: radial-gradient(ellipse at top left, rgba(59,130,246,.2), transparent 60%),
              radial-gradient(ellipse at bottom right, rgba(16,185,129,.15), transparent 60%);
}

.hero-content { position: relative; z-index: 1; }

.hero-badge {
  display: inline-block;
  background: rgba(255,255,255,.12);
  border: 1px solid rgba(255,255,255,.25);
  border-radius: 20px;
  padding: 4px 14px;
  font-size: 0.77rem;
  font-weight: 600;
  letter-spacing: .5px;
  margin-bottom: 14px;
  text-transform: uppercase;
}

.hero-title {
  font-size: 2.6rem;
  font-weight: 900;
  line-height: 1.1;
  margin-bottom: 12px;
}

.gradient-text {
  background: linear-gradient(90deg, #86efac, #67e8f9);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.hero-sub {
  font-size: 1rem;
  opacity: .8;
  margin-bottom: 20px;
  max-width: 480px;
}

.hero-actions { display: flex; gap: 10px; flex-wrap: wrap; }

.btn-hero-primary {
  background: white;
  color: #1e3a5f;
  border: none;
  font-weight: 700;
  padding: 10px 24px;
  border-radius: 24px;
  font-size: 0.9rem;
  cursor: pointer;
  transition: all var(--transition);
}
.btn-hero-primary:hover { transform: translateY(-2px); box-shadow: 0 6px 18px rgba(0,0,0,.25); }

.btn-hero-secondary {
  background: rgba(255,255,255,.12);
  color: white;
  border: 1px solid rgba(255,255,255,.3);
  font-weight: 600;
  padding: 10px 24px;
  border-radius: 24px;
  font-size: 0.9rem;
  cursor: pointer;
  transition: all var(--transition);
}
.btn-hero-secondary:hover { background: rgba(255,255,255,.2); }

.hero-visual {
  position: relative;
  z-index: 1;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  width: 200px;
}

.float-card {
  background: rgba(255,255,255,.12);
  border: 1px solid rgba(255,255,255,.2);
  border-radius: 12px;
  padding: 12px 8px;
  text-align: center;
  backdrop-filter: blur(4px);
  animation: float 3s ease-in-out infinite;
}

.float-card:nth-child(2) { animation-delay: .5s; }
.float-card:nth-child(3) { animation-delay: 1s; }
.float-card:nth-child(4) { animation-delay: 1.5s; }

.float-card span { font-size: 1.5rem; display: block; }
.float-card small { font-size: 0.7rem; opacity: .8; }

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50%       { transform: translateY(-5px); }
}

@media (max-width: 768px) {
  .hero-banner { grid-template-columns: 1fr; }
  .hero-visual { display: none; }
  .hero-title  { font-size: 1.8rem; }
}

/* ── App Container ──────────────────────────────── */
.app-container { padding-top: 20px; padding-bottom: 80px; }

/* ── Profile Bar ────────────────────────────────── */
.profile-bar { border-radius: var(--radius); }
.form-label-sm {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: .4px;
  display: block;
  margin-bottom: 3px;
}

/* ── Cards ──────────────────────────────────────── */
.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-sm);
  transition: box-shadow var(--transition), background var(--transition);
}
.card:hover { box-shadow: var(--shadow-md); }
.card-header {
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  border-radius: var(--radius) var(--radius) 0 0 !important;
  padding: 13px 18px;
  font-size: 0.88rem;
  font-weight: 600;
  color: var(--text);
}
.card-body  { padding: 18px; }
.card-footer { padding: 12px 18px; background: var(--surface-2); border-top: 1px solid var(--border); border-radius: 0 0 var(--radius) var(--radius); }

/* ── Tab Panes ──────────────────────────────────── */
.tab-pane { display: none; animation: fadeSlide .25s ease; }
.tab-pane.active { display: block; }

@keyframes fadeSlide {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ── Chat ───────────────────────────────────────── */
.chat-card { display: flex; flex-direction: column; min-height: 520px; max-height: 680px; }

.agent-avatar {
  font-size: 1.6rem;
  width: 36px; height: 36px;
  display: flex; align-items: center; justify-content: center;
}

.status-dot-wrap { display: flex; align-items: center; gap: 5px; }
.status-dot {
  width: 8px; height: 8px;
  background: var(--c-green);
  border-radius: 50%;
  animation: pulse 2s infinite;
}
@keyframes pulse { 0%,100%{opacity:1;} 50%{opacity:.4;} }

.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
  min-height: 0;
}

.chat-input-wrap {
  border-top: 1px solid var(--border);
}

.quick-prompts {
  padding: 10px 14px 6px;
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.qp-chip {
  background: var(--surface-2);
  border: 1px solid var(--border);
  color: var(--text-2);
  border-radius: 16px;
  padding: 4px 11px;
  font-size: 0.77rem;
  cursor: pointer;
  transition: all var(--transition);
  white-space: nowrap;
}
.qp-chip:hover {
  background: rgba(59,130,246,.1);
  border-color: var(--c-accent);
  color: var(--c-accent);
  transform: translateY(-1px);
}

.input-group {
  padding: 10px 14px 14px;
  display: flex;
  gap: 8px;
  align-items: flex-end;
}

.input-group .form-control {
  resize: none;
  border-radius: 12px;
  font-size: 0.88rem;
  max-height: 110px;
  overflow-y: auto;
  background: var(--surface-2);
  border-color: var(--border);
  color: var(--text);
}

.input-group .form-control:focus {
  background: var(--surface-2);
  color: var(--text);
  border-color: var(--c-accent);
  box-shadow: 0 0 0 3px rgba(59,130,246,.15);
}

.btn-send {
  width: 42px; height: 42px;
  background: var(--c-accent);
  border: none;
  border-radius: 12px;
  color: white;
  font-size: 1rem;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
  transition: all var(--transition);
}
.btn-send:hover { background: var(--c-accent-d); transform: translateY(-1px); }

/* Chat Bubbles */
.bubble-wrap { display: flex; flex-direction: column; max-width: 83%; }
.bubble-wrap.user { align-self: flex-end; align-items: flex-end; }
.bubble-wrap.ai   { align-self: flex-start; align-items: flex-start; }

.bubble {
  padding: 11px 15px;
  border-radius: 16px;
  font-size: 0.875rem;
  line-height: 1.65;
  word-break: break-word;
  animation: bubbleIn .22s ease;
}
@keyframes bubbleIn { from{opacity:0;transform:scale(.95) translateY(5px)} to{opacity:1;transform:scale(1) translateY(0)} }

.bubble.user {
  background: var(--c-accent);
  color: white;
  border-bottom-right-radius: 4px;
}
.bubble.ai {
  background: var(--surface-2);
  color: var(--text);
  border: 1px solid var(--border);
  border-bottom-left-radius: 4px;
}

.bubble-time { font-size: 0.7rem; color: var(--text-muted); margin-top: 3px; padding: 0 2px; }

/* Typing indicator */
.typing-bubble {
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 16px;
  border-bottom-left-radius: 4px;
  padding: 12px 16px;
  display: flex; gap: 5px; align-items: center;
  align-self: flex-start;
}
.t-dot {
  width: 7px; height: 7px; border-radius: 50%;
  background: var(--text-muted);
  animation: typing 1.1s infinite;
}
.t-dot:nth-child(2){animation-delay:.2s}
.t-dot:nth-child(3){animation-delay:.4s}
@keyframes typing { 0%,80%,100%{transform:scale(1);opacity:.5} 40%{transform:scale(1.4);opacity:1} }

/* AI response formatting */
.bubble.ai h1,.bubble.ai h2 { font-size: 1rem; font-weight: 700; margin: 10px 0 4px; }
