}

.input-group .form-control:focus {
  background: var(--surface-2);
  color: var(--text);
  border-color: var(--c-accent);
  box-shadow: 0 0 0 3px rgba(59,130,246,.15);
}

.btn-send {
  width: 42px; height: 42px;
  background: var(--c-accent);
  border: none;
  border-radius: 12px;
  color: white;
  font-size: 1rem;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
  transition: all var(--transition);
}
.btn-send:hover { background: var(--c-accent-d); transform: translateY(-1px); }

/* Chat Bubbles */
.bubble-wrap { display: flex; flex-direction: column; max-width: 83%; }
.bubble-wrap.user { align-self: flex-end; align-items: flex-end; }
.bubble-wrap.ai   { align-self: flex-start; align-items: flex-start; }

.bubble {
  padding: 11px 15px;
  border-radius: 16px;
  font-size: 0.875rem;
  line-height: 1.65;
  word-break: break-word;
  animation: bubbleIn .22s ease;
}
@keyframes bubbleIn { from{opacity:0;transform:scale(.95) translateY(5px)} to{opacity:1;transform:scale(1) translateY(0)} }

.bubble.user {
  background: var(--c-accent);
  color: white;
  border-bottom-right-radius: 4px;
}
.bubble.ai {
  background: var(--surface-2);
  color: var(--text);
  border: 1px solid var(--border);
  border-bottom-left-radius: 4px;
}

.bubble-time { font-size: 0.7rem; color: var(--text-muted); margin-top: 3px; padding: 0 2px; }

/* Typing indicator */
.typing-bubble {
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: 16px;
  border-bottom-left-radius: 4px;
  padding: 12px 16px;
  display: flex; gap: 5px; align-items: center;
  align-self: flex-start;
}
.t-dot {
  width: 7px; height: 7px; border-radius: 50%;
  background: var(--text-muted);
  animation: typing 1.1s infinite;
}
.t-dot:nth-child(2){animation-delay:.2s}
.t-dot:nth-child(3){animation-delay:.4s}
@keyframes typing { 0%,80%,100%{transform:scale(1);opacity:.5} 40%{transform:scale(1.4);opacity:1} }

/* AI response formatting */
.bubble.ai h1,.bubble.ai h2 { font-size: 1rem; font-weight: 700; margin: 10px 0 4px; }
.bubble.ai h3,.bubble.ai h4 { font-size: .9rem; font-weight: 700; margin: 8px 0 3px; color: var(--c-accent); }
.bubble.ai ul,.bubble.ai ol  { padding-left: 18px; margin: 6px 0; }
.bubble.ai table { width:100%; border-collapse:collapse; font-size:.82rem; margin:6px 0; }
.bubble.ai th,.bubble.ai td  { border:1px solid var(--border); padding:5px 9px; }
.bubble.ai th { background:var(--surface); font-weight:600; }
.bubble.ai blockquote { border-left:3px solid var(--c-accent); padding-left:10px; color:var(--text-muted); margin:8px 0; font-style:italic; }
.bubble.ai hr { border-color:var(--border); margin:8px 0; }
.bubble.ai code { background:var(--surface); border-radius:4px; padding:1px 5px; font-size:.82rem; }

/* Sidebar info cards */
.info-card { background: var(--surface); }
.card-title-sm { font-size: .82rem; font-weight: 700; color: var(--text); margin-bottom: 8px; }
.tip-text { font-size: .83rem; color: var(--text-2); line-height: 1.6; }

/* Hydration */
.hydration-glasses { display:flex; flex-wrap:wrap; gap:4px; }
.glass-icon { font-size:1.3rem; cursor:default; }
.btn-xs { font-size:.75rem; padding:2px 8px; border-radius:6px; }
.btn-outline-primary { border-color:var(--c-accent); color:var(--c-accent); background:transparent; }
.btn-outline-primary:hover { background:var(--c-accent); color:white; }

/* History list */
.history-list { max-height: 180px; overflow-y: auto; }
.history-item {
  padding: 6px 8px;
  border-radius: 8px;
  font-size: .8rem;
  color: var(--text-2);
  cursor: pointer;
  border-bottom: 1px solid var(--border);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.history-item:hover { background: var(--surface-2); }

/* ── Dashboard ──────────────────────────────────── */
.stat-card {
  padding: 18px 14px;
  text-align: center;
  border-radius: var(--radius);
  transition: all var(--transition);
}
.stat-card:hover { transform: translateY(-3px); box-shadow: var(--shadow-lg); }
.stat-icon {
  font-size: 1.6rem;
  width: 44px; height: 44px;
  border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  margin: 0 auto 10px;
}
.stat-value { font-size: 1.8rem; font-weight: 800; color: var(--text); line-height: 1; }
.stat-label { font-size: .78rem; font-weight: 600; color: var(--text-muted); margin-top: 4px; }

/* Macro ring */
.macro-ring-wrap { position: relative; }
.macro-ring { width: 160px; height: 160px; }
.ring-label-main { font-size: 18px; font-weight: 800; fill: var(--text); }
.ring-label-sub  { font-size: 10px; fill: var(--text-muted); }
.macro-legend { display:flex; gap:14px; justify-content:center; }
.legend-item { font-size:.8rem; color:var(--text-muted); display:flex; align-items:center; gap:5px; }
.legend-dot  { width:10px;height:10px;border-radius:50%; }

/* Analysis result */
.analysis-result {
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 14px;
  font-size: .85rem;
  white-space: pre-wrap;
  color: var(--text);
  max-height: 320px;
  overflow-y: auto;
}

/* ── Meal Plan ──────────────────────────────────── */
.check-grid { display:grid; grid-template-columns:1fr 1fr; gap:6px; }
.form-check-label { font-size:.84rem; color:var(--text-2); }
.meal-plan-body { min-height: 300px; }
.empty-state { text-align:center; padding:48px 16px; color:var(--text-muted); }
.empty-icon  { font-size:3rem; margin-bottom:14px; }
.meal-plan-output-text {
  white-space: pre-wrap;
  font-size: .86rem;
  line-height: 1.8;
  color: var(--text);
}

/* ── BMI ────────────────────────────────────────── */
.bmi-scale {
  display: flex;
  border-radius: 10px;
  overflow: hidden;
  margin: 10px 0 6px;
}
.bmi-segment {
  flex: 1;
  padding: 10px 6px;
  text-align: center;
  color: white;
  font-size: .75rem;
  font-weight: 600;
}
.bmi-segment span  { display:block; font-weight:700; }
.bmi-segment small { opacity:.85; }

.bmi-result-wrap {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  margin-bottom: 16px;
}

.bmi-big-number {
  font-size: 3.5rem;
  font-weight: 900;
  line-height: 1;
  background: linear-gradient(135deg, var(--c-accent), var(--c-green));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.bmi-badge-cat {
  display: inline-block;
  padding: 4px 14px;
  border-radius: 20px;
  font-size: .85rem;
  font-weight: 700;
  margin-top: 6px;
}

.macro-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
  margin-top: 12px;
}

.macro-cell {
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px;
  text-align: center;
}

.macro-cell-val  { font-size: 1.3rem; font-weight: 800; }
.macro-cell-label{ font-size: .72rem; color: var(--text-muted); text-transform: uppercase; }

/* ── Family ─────────────────────────────────────── */
.family-member-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--surface-2);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px 12px;
  margin-bottom: 8px;
  animation: fadeSlide .2s ease;
}
.fm-info strong { font-size:.88rem; color:var(--text); }
.fm-info small  { font-size:.75rem; color:var(--text-muted); }
.fm-remove { background:none; border:none; color:var(--c-red); font-size:.9rem; cursor:pointer; padding:2px 7px; border-radius:6px; }
.fm-remove:hover { background:rgba(239,68,68,.1); }

.family-plan-body { min-height: 300px; }

/* ── Superfoods ─────────────────────────────────── */
.section-heading { font-size:.85rem; font-weight:700; color:var(--text-muted); text-transform:uppercase; letter-spacing:.5px; }
.superfood-chip {
  display: flex;
  align-items: center;
  gap: 8px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 10px 12px;
  transition: all var(--transition);
}
.superfood-chip:hover { border-color: var(--c-green); transform: translateY(-2px); box-shadow: var(--shadow-md); }
.sf-em  { font-size: 1.5rem; }
.sf-nm  { font-size: .85rem; font-weight: 700; color: var(--text); }
.sf-sub { font-size: .72rem; color: var(--text-muted); }

/* AI Superfoods output */
.superfoods-output {
  white-space: pre-wrap;
  font-size: .86rem;
  line-height: 1.8;
  color: var(--text);
}

/* ── Accent Button ──────────────────────────────── */
.btn-accent {
  background: linear-gradient(135deg, var(--c-accent), var(--c-green));
  border: none;
  color: white;
  font-weight: 700;
  border-radius: 10px;
  font-size: .88rem;
  transition: all var(--transition);
}
.btn-accent:hover { transform: translateY(-1px); box-shadow: 0 4px 14px rgba(59,130,246,.35); color: white; }

/* ── Forms ──────────────────────────────────────── */
.form-control, .form-select {
  background: var(--surface-2);
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: var(--radius-sm);
  font-size: .88rem;
  transition: border var(--transition), background var(--transition);
}
.form-control:focus, .form-select:focus {
  background: var(--surface-2);
  color: var(--text);
  border-color: var(--c-accent);
  box-shadow: 0 0 0 3px rgba(59,130,246,.15);
}
.form-label { font-size: .84rem; font-weight: 500; color: var(--text-2); margin-bottom: 5px; }
.form-range { accent-color: var(--c-accent); }
.form-check-input:checked { background-color: var(--c-accent); border-color: var(--c-accent); }

/* ── Modal ──────────────────────────────────────── */
.modal-content {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
}
.modal-header { border-bottom-color: var(--border); }
.modal-footer { border-top-color: var(--border); }
.btn-close { filter: var(--bs-btn-close-filter, none); }
[data-theme="dark"] .btn-close { filter: invert(1); }

/* ── Loading Overlay ────────────────────────────── */
.loading-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,.5);
  backdrop-filter: blur(3px);
  z-index: 9999;
  display: flex; align-items: center; justify-content: center;
}
.loading-box {
  background: var(--surface);
  border-radius: var(--radius);
  padding: 32px 40px;
  text-align: center;
  box-shadow: var(--shadow-lg);
}
.loading-text { font-size: .92rem; color: var(--text-muted); margin-top: 4px; }
.text-accent { color: var(--c-accent); }

/* ── Toast ──────────────────────────────────────── */
.toast {
  background: var(--surface);
  border: 1px solid var(--border);
  color: var(--text);
  border-radius: 12px;
  font-size: .85rem;
  box-shadow: var(--shadow-md);
}

/* ── Footer ─────────────────────────────────────── */
.app-footer {
  position: fixed; bottom: 0; left: 0; right: 0;
  background: var(--nav-bg);
  border-top: 1px solid var(--border);
  padding: 10px 20px;
  font-size: .78rem;
  color: var(--text-muted);
  display: flex; align-items: center; gap: 10px;
  z-index: 100;
}
.footer-sep { opacity: .3; }

/* ── Responsive ─────────────────────────────────── */
@media (max-width: 992px) {
  .chat-card { max-height: 560px; }
}
@media (max-width: 576px) {
  .hero-title { font-size: 1.5rem; }
  .bmi-result-wrap { grid-template-columns: 1fr; }
  .macro-grid { grid-template-columns: 1fr 1fr; }
  .app-footer { font-size: .7rem; }
  .profile-bar { display: none; }
}

/* ── Print ───────────────────────────────────────── */
@media print {
  #mainNav, .hero-banner, .app-footer, .quick-prompts,
  .chat-input-wrap, .profile-bar, .loading-overlay { display: none !important; }
  .card { box-shadow: none !important; border: 1px solid #ddd !important; }
  body { background: white !important; color: black !important; }
}

