// ════════════════════════════════════════════════════════════════════
//  NutriAI — Frontend Application Logic
//  Handles: chat, dashboard, meal planning, BMI, family profiles, dark mode
// ════════════════════════════════════════════════════════════════════

/* ── Global State ───────────────────────────────────────────────── */
let currentProfile = {};
let familyMembers = [];
let glassesOfWater = 0;
let chatHistory = [];

/* ── On Page Load ───────────────────────────────────────────────── */
document.addEventListener('DOMContentLoaded', () => {
  initApp();
});

function initApp() {
  // Load persisted data from localStorage
  loadProfile();
  loadFamilyMembers();
  loadWaterTracking();
  loadDarkMode();

  // Set up tab navigation
  setupTabs();

  // Show welcome message in chat
  showWelcomeMessage();

  // Load daily tip
  loadDailyTip();

  // Render initial superfood chips
  renderSuperfoodChips();

  // Update dashboard with profile if available
  updateDashboardFromProfile();

  // Check health status
  checkHealth();

  // Hide hero banner after a short delay
  setTimeout(() => {
    const hero = document.getElementById('heroBanner');
    if (hero) {
      hero.style.transition = 'opacity .4s ease';
      hero.style.opacity = '0';
      setTimeout(() => hero.style.display = 'none', 400);
    }
  }, 3500);
}

/* ── Tab Navigation ─────────────────────────────────────────────── */
function setupTabs() {
  const navLinks = document.querySelectorAll('[data-tab]');
  navLinks.forEach(link => {
    link.addEventListener('click', (e) => {
      e.preventDefault();
      const tabName = link.getAttribute('data-tab');
      switchTab(tabName);

      // Update active nav link
      navLinks.forEach(l => l.classList.remove('active'));
      link.classList.add('active');
    });
  });
}

function switchTab(tabName) {
  const panes = document.querySelectorAll('.tab-pane');
  panes.forEach(pane => pane.classList.remove('active'));

  const targetPane = document.getElementById(`tab-${tabName}`);
  if (targetPane) {
    targetPane.classList.add('active');
  }

  // Close mobile menu if open
  const navCollapse = document.getElementById('navMenu');
  if (navCollapse && navCollapse.classList.contains('show')) {
    bootstrap.Collapse.getInstance(navCollapse)?.hide();
  }
}

/* ── Dark Mode ──────────────────────────────────────────────────── */
function loadDarkMode() {
  const savedTheme = localStorage.getItem('theme') || 'light';
  document.documentElement.setAttribute('data-theme', savedTheme);
  updateThemeIcon(savedTheme);
}

function toggleDarkMode() {
  const current = document.documentElement.getAttribute('data-theme');
  const newTheme = current === 'dark' ? 'light' : 'dark';
  document.documentElement.setAttribute('data-theme', newTheme);
  localStorage.setItem('theme', newTheme);
  updateThemeIcon(newTheme);
}

function updateThemeIcon(theme) {
  const icon = document.querySelector('.theme-toggle i');
  if (icon) {
    icon.className = theme === 'dark' ? 'bi bi-sun-fill' : 'bi bi-moon-stars-fill';
  }
}

document.getElementById('themeToggle')?.addEventListener('click', toggleDarkMode);

/* ── Profile Management ─────────────────────────────────────────── */
function saveProfile() {
  currentProfile = {
    name: document.getElementById('pName')?.value || '',
    age: parseInt(document.getElementById('pAge')?.value) || 25,
    weight: parseFloat(document.getElementById('pWeight')?.value) || 65,
    height: parseFloat(document.getElementById('pHeight')?.value) || 165,
    gender: document.getElementById('pGender')?.value || 'female',
    diet: document.getElementById('pDiet')?.value || 'vegetarian',
    goal: document.getElementById('pGoal')?.value || 'maintain health',
    condition: document.getElementById('pCondition')?.value || 'none',
  };

  localStorage.setItem('nutriai_profile', JSON.stringify(currentProfile));
  updateDashboardFromProfile();
  showToast('✅ Profile saved!');
}

function loadProfile() {
  const saved = localStorage.getItem('nutriai_profile');
  if (saved) {
    currentProfile = JSON.parse(saved);

    // Populate form fields
    if (document.getElementById('pName')) document.getElementById('pName').value = currentProfile.name || '';
    if (document.getElementById('pAge')) document.getElementById('pAge').value = currentProfile.age || '';
    if (document.getElementById('pWeight')) document.getElementById('pWeight').value = currentProfile.weight || '';
    if (document.getElementById('pHeight')) document.getElementById('pHeight').value = currentProfile.height || '';
    if (document.getElementById('pDiet')) document.getElementById('pDiet').value = currentProfile.diet || 'vegetarian';
    if (document.getElementById('pGoal')) document.getElementById('pGoal').value = currentProfile.goal || 'maintain health';
    if (document.getElementById('pCondition')) document.getElementById('pCondition').value = currentProfile.condition || 'none';
  }
}

function updateDashboardFromProfile() {
  if (!currentProfile.weight || !currentProfile.height || !currentProfile.age) {
    return;
  }

  // Calculate BMR and TDEE
  const bmr = calculateBMR(currentProfile.weight, currentProfile.height, currentProfile.age, currentProfile.gender || 'female');
  const tdee = Math.round(bmr * 1.55);
  const protein = Math.round(currentProfile.weight * 1.3);
  const carbs = Math.round((tdee * 0.45) / 4);
  const fat = Math.round((tdee * 0.30) / 9);

  document.getElementById('statCalories').textContent = tdee;
  document.getElementById('statProtein').textContent = `${protein}g`;
  document.getElementById('statCarbs').textContent = `${carbs}g`;
  document.getElementById('statFat').textContent = `${fat}g`;
  document.getElementById('ringCalText').textContent = tdee;

  // Update macro ring arcs (SVG arcs — stroke-dasharray)
  const proteinPct = (protein * 4) / tdee;
  const carbsPct = (carbs * 4) / tdee;
  const fatPct = (fat * 9) / tdee;

  const circumference = 2 * Math.PI * 50;
  document.getElementById('macroProteinArc')?.setAttribute('stroke-dasharray', `${proteinPct * circumference} ${circumference}`);
  document.getElementById('macroCarbsArc')?.setAttribute('stroke-dasharray', `${carbsPct * circumference} ${circumference}`);
  document.getElementById('macroFatArc')?.setAttribute('stroke-dasharray', `${fatPct * circumference} ${circumference}`);
}

function calculateBMR(weight, height, age, gender) {
  if (gender === 'male') {
    return 10 * weight + 6.25 * height - 5 * age + 5;
  } else {
    return 10 * weight + 6.25 * height - 5 * age - 161;
  }
}

/* ── Chat Functionality ─────────────────────────────────────────── */
function showWelcomeMessage() {
  const messagesDiv = document.getElementById('chatMessages');
  if (!messagesDiv) return;

  const welcomeMsg = `👋 Hi! I'm **NutriAI**, your personal nutrition assistant powered by IBM Watsonx.ai.

I can help you with:
🥗 **Personalized meal plans** (7-day Indian & international)
🔥 **Calorie & nutrient analysis** for any food
📊 **BMI & TDEE calculation** with macro targets
👨‍👩‍👧 **Family nutrition plans** for all ages
🌿 **Indian superfoods** and their benefits
🏥 **Condition-specific diets** (diabetes, PCOS, thyroid, heart health)

✨ **Quick Start:** Try clicking one of the chips below or ask me anything about nutrition!

_Powered by IBM Granite LLM · Built with care for Indian dietary needs_ 🇮🇳`;

  addChatBubble('ai', welcomeMsg);
}

function sendMessage() {
  const input = document.getElementById('chatInput');
  if (!input) return;

  const message = input.value.trim();
  if (!message) return;

  addChatBubble('user', message);
  input.value = '';
  input.style.height = 'auto';

  showTypingIndicator();
  chatHistory.push({ role: 'user', content: message });

  fetch('/api/chat', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ message, profile: currentProfile }),
  })
  .then(res => res.json())
  .then(data => {
    removeTypingIndicator();
    addChatBubble('ai', data.response);
    chatHistory.push({ role: 'assistant', content: data.response });
    saveChatHistory();
  })
  .catch(err => {
    removeTypingIndicator();
    addChatBubble('ai', '⚠️ Sorry, I encountered an error. Please try again.');
    console.error('Chat error:', err);
  });
}

function sendQuick(prompt) {
  document.getElementById('chatInput').value = prompt;
  sendMessage();
}

function handleChatKey(event) {
  if (event.key === 'Enter' && !event.shiftKey) {
    event.preventDefault();
    sendMessage();
  }
}

function addChatBubble(role, text) {
  const messagesDiv = document.getElementById('chatMessages');
  if (!messagesDiv) return;

  const wrapDiv = document.createElement('div');
  wrapDiv.className = `bubble-wrap ${role}`;

  const bubbleDiv = document.createElement('div');
  bubbleDiv.className = `bubble ${role}`;
  bubbleDiv.innerHTML = formatMarkdown(text);

  const timeDiv = document.createElement('div');
  timeDiv.className = 'bubble-time';
  timeDiv.textContent = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });

  wrapDiv.appendChild(bubbleDiv);
  wrapDiv.appendChild(timeDiv);
  messagesDiv.appendChild(wrapDiv);
  messagesDiv.scrollTop = messagesDiv.scrollHeight;
}

function showTypingIndicator() {
  const messagesDiv = document.getElementById('chatMessages');
  if (!messagesDiv) return;

  const typing = document.createElement('div');
  typing.className = 'typing-bubble';
  typing.id = 'typingIndicator';
  typing.innerHTML = '<span class="t-dot"></span><span class="t-dot"></span><span class="t-dot"></span>';
  messagesDiv.appendChild(typing);
  messagesDiv.scrollTop = messagesDiv.scrollHeight;
}

function removeTypingIndicator() {
  document.getElementById('typingIndicator')?.remove();
}

function clearChat() {
  if (!confirm('Clear all chat messages?')) return;
  document.getElementById('chatMessages').innerHTML = '';
  chatHistory = [];
  localStorage.removeItem('nutriai_chat');
  fetch('/api/clear-chat', { method: 'POST' });
  showWelcomeMessage();
  showToast('Chat cleared');
}

function saveChatHistory() {
  localStorage.setItem('nutriai_chat', JSON.stringify(chatHistory.slice(-20)));
}

/* ── Markdown Formatter ─────────────────────────────────────────── */
function formatMarkdown(text) {
  return text
    .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/`(.+?)`/g, '<code>$1</code>')
    .replace(/^> (.+)$/gm, '<blockquote>$1</blockquote>')
    .replace(/^---$/gm, '<hr />')
    .replace(/\n/g, '<br />');
}

/* ── Hydration Tracker ──────────────────────────────────────────── */
function loadWaterTracking() {
  glassesOfWater = parseInt(localStorage.getItem('nutriai_water')) || 0;
  renderWaterGlasses();
}

function addGlass() {
  if (glassesOfWater >= 8) {
    showToast('🎉 You\'ve reached your daily goal!');
    return;
  }
  glassesOfWater++;
  localStorage.setItem('nutriai_water', glassesOfWater);
  renderWaterGlasses();
  if (glassesOfWater === 8) {
    showToast('💧 Awesome! You\'ve hit your hydration target!');
  }
}

function renderWaterGlasses() {
  const container = document.getElementById('hydrationGlasses');
  const countSpan = document.getElementById('glassCount');
  const bar = document.getElementById('hydrationBar');

  if (container) {
    container.innerHTML = Array.from({ length: glassesOfWater }, () => '<span class="glass-icon">💧</span>').join('');
  }
  if (countSpan) countSpan.textContent = glassesOfWater;
  if (bar) bar.style.width = `${(glassesOfWater / 8) * 100}%`;
}

/* ── Daily Tip ──────────────────────────────────────────────────── */
function loadDailyTip() {
  const tips = [
    "Start your day with warm lemon water to boost digestion and metabolism.",
    "Include colorful vegetables in every meal to get a variety of vitamins.",
    "Aim for at least 8 glasses of water daily to stay hydrated.",
    "Replace refined grains with whole grains like brown rice and whole wheat.",
    "Eat a handful of nuts daily for healthy fats and protein.",
    "Limit processed foods and sugary drinks for better overall health.",
    "Practice mindful eating — chew slowly and savor each bite.",
    "Add turmeric to your meals for its anti-inflammatory benefits.",
    "Don't skip breakfast — it kickstarts your metabolism.",
    "Get at least 7-8 hours of quality sleep to support healthy weight management.",
  ];
  const randomTip = tips[Math.floor(Math.random() * tips.length)];
  const tipEl = document.getElementById('dailyTip');
  if (tipEl) tipEl.textContent = randomTip;
}

/* ── Meal Analysis ──────────────────────────────────────────────── */
function analyzeMeal() {
  const input = document.getElementById('mealAnalyzeInput');
  const resultDiv = document.getElementById('mealAnalysisResult');
  if (!input || !resultDiv) return;

  const meal = input.value.trim();
  if (!meal) {
    showToast('Please describe your meal');
    return;
  }

  showLoading('Analyzing meal nutrition...');

  fetch('/api/analyze-meal', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ meal }),
  })
  .then(res => res.json())
  .then(data => {
    hideLoading();
    resultDiv.textContent = data.analysis;
    resultDiv.classList.remove('d-none');
    showToast('✅ Analysis complete!');
  })
  .catch(err => {
    hideLoading();
    showToast('⚠️ Error analyzing meal');
    console.error(err);
  });
}

/* ── Meal Plan Generation ───────────────────────────────────────── */
function generateMealPlan() {
  const output = document.getElementById('mealPlanOutput');
  if (!output) return;

  const profile = {
    ...currentProfile,
    diet_type: currentProfile.diet || document.getElementById('pDiet')?.value || 'vegetarian',
    goal: currentProfile.goal || document.getElementById('pGoal')?.value || 'maintain health',
    calories: document.getElementById('calorieSlider')?.value || 1600,
    cuisine: document.getElementById('cuisinePref')?.value || 'mixed Indian',
  };

  showLoading('NutriAI is creating your personalized meal plan...');

  fetch('/api/meal-plan', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ profile }),
  })
  .then(res => res.json())
  .then(data => {
    hideLoading();
    output.innerHTML = `<div class="meal-plan-output-text">${formatMarkdown(data.meal_plan)}</div>`;
    document.getElementById('copyPlanBtn')?.classList.remove('d-none');
    showToast('✅ Meal plan generated!');
  })
  .catch(err => {
    hideLoading();
    output.innerHTML = '<div class="empty-state"><div class="empty-icon">⚠️</div><p>Error generating meal plan. Please try again.</p></div>';
    console.error(err);
  });
}

function copyPlan() {
  const text = document.querySelector('.meal-plan-output-text')?.innerText;
  if (text) {
    navigator.clipboard.writeText(text).then(() => showToast('📋 Copied to clipboard!'));
  }
}

/* ── BMI Calculator ─────────────────────────────────────────────── */
function calculateBMI() {
  const weight = parseFloat(document.getElementById('bmiWeight')?.value);
  const height = parseFloat(document.getElementById('bmiHeight')?.value);
  const age = parseInt(document.getElementById('bmiAge')?.value);
  const gender = document.getElementById('bmiGender')?.value || 'female';
  const activity = document.getElementById('bmiActivity')?.value || 'moderate';

  if (!weight || !height || !age) {
    showToast('Please fill in all fields');
    return;
  }

  showLoading('Calculating your BMI & nutrition needs...');

  fetch('/api/bmi', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ weight, height, age, gender, activity }),
  })
  .then(res => res.json())
  .then(data => {
    hideLoading();
    renderBMIResults(data);
  })
  .catch(err => {
    hideLoading();
    showToast('⚠️ Error calculating BMI');
    console.error(err);
  });
}

function renderBMIResults(data) {
  const resultsDiv = document.getElementById('bmiResults');
  if (!resultsDiv) return;

  const categoryColor = {
    'Underweight': '#3b9ddd',
    'Normal Weight': '#2ecc71',
    'Overweight': '#f39c12',
    'Obese': '#e74c3c',
  };

  const html = `
    <div class="text-center mb-4">
      <div class="bmi-big-number">${data.bmi}</div>
      <div class="bmi-badge-cat" style="background:${categoryColor[data.category] || '#gray'}; color:white;">
        ${data.category}
      </div>
      <p class="text-muted mt-2 small">${data.advice}</p>
    </div>

    <div class="bmi-result-wrap">
      <div class="macro-cell">
        <div class="macro-cell-label">BMR</div>
        <div class="macro-cell-val">${data.bmr}</div>
        <small class="text-muted">kcal/day</small>
      </div>
      <div class="macro-cell">
        <div class="macro-cell-label">TDEE</div>
        <div class="macro-cell-val">${data.tdee}</div>
        <small class="text-muted">kcal/day</small>
      </div>
    </div>

    <div class="macro-grid">
      <div class="macro-cell">
        <div class="macro-cell-label">Weight Loss</div>
        <div class="macro-cell-val" style="color:var(--c-orange)">${data.weight_loss}</div>
        <small class="text-muted">kcal/day</small>
      </div>
      <div class="macro-cell">
        <div class="macro-cell-label">Weight Gain</div>
        <div class="macro-cell-val" style="color:var(--c-purple)">${data.weight_gain}</div>
        <small class="text-muted">kcal/day</small>
      </div>
      <div class="macro-cell">
        <div class="macro-cell-label">Protein Target</div>
        <div class="macro-cell-val" style="color:var(--c-accent)">${data.protein_g}g</div>
      </div>
      <div class="macro-cell">
        <div class="macro-cell-label">Ideal Weight</div>
        <div class="macro-cell-val" style="color:var(--c-green)">${data.ideal_weight_min}–${data.ideal_weight_max} kg</div>
      </div>
    </div>
  `;

  resultsDiv.innerHTML = html;
}

/* ── Family Members ─────────────────────────────────────────────── */
function loadFamilyMembers() {
  const saved = localStorage.getItem('nutriai_family');
  if (saved) {
    familyMembers = JSON.parse(saved);
    renderFamilyMembers();
  }
}

function addFamilyMember() {
  const modal = new bootstrap.Modal(document.getElementById('familyModal'));
  modal.show();
}

function saveFamilyMember() {
  const member = {
    name: document.getElementById('fmName')?.value || '',
    age: parseInt(document.getElementById('fmAge')?.value) || 0,
    gender: document.getElementById('fmGender')?.value || '',
    relation: document.getElementById('fmRelation')?.value || '',
    condition: document.getElementById('fmCondition')?.value || 'healthy',
    diet: document.getElementById('fmDiet')?.value || 'Vegetarian',
  };

  if (!member.name || !member.age) {
    showToast('Name and age are required');
    return;
  }

  familyMembers.push(member);
  localStorage.setItem('nutriai_family', JSON.stringify(familyMembers));
  renderFamilyMembers();

  // Close modal
  const modalEl = document.getElementById('familyModal');
  const modal = bootstrap.Modal.getInstance(modalEl);
  modal?.hide();

  // Clear form
  document.getElementById('fmName').value = '';
  document.getElementById('fmAge').value = '';

  showToast('✅ Family member added');
}

function renderFamilyMembers() {
  const container = document.getElementById('familyMembersList');
  if (!container) return;

  if (familyMembers.length === 0) {
    container.innerHTML = '<p class="text-muted small text-center py-3">No family members added yet.</p>';
    return;
  }

  container.innerHTML = familyMembers.map((m, i) => `
    <div class="family-member-row">
      <div class="fm-info">
        <strong>${m.name}</strong>
        <small class="d-block">${m.age} yrs · ${m.gender} · ${m.relation}</small>
        <small class="d-block text-muted">${m.condition !== 'healthy' ? m.condition : 'Healthy'}</small>
      </div>
      <button class="fm-remove" onclick="removeFamilyMember(${i})">
        <i class="bi bi-x-lg"></i>
      </button>
    </div>
  `).join('');
}

function removeFamilyMember(index) {
  familyMembers.splice(index, 1);
  localStorage.setItem('nutriai_family', JSON.stringify(familyMembers));
  renderFamilyMembers();
  showToast('Member removed');
}

function generateFamilyPlan() {
  if (familyMembers.length === 0) {
    showToast('Please add at least one family member');
    return;
  }

  const output = document.getElementById('familyPlanOutput');
  if (!output) return;

  showLoading('Creating family nutrition plan...');

  fetch('/api/family-plan', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ members: familyMembers }),
  })
  .then(res => res.json())
  .then(data => {
    hideLoading();
    output.innerHTML = `<div class="meal-plan-output-text">${formatMarkdown(data.family_plan)}</div>`;
    showToast('✅ Family plan generated!');
  })
  .catch(err => {
    hideLoading();
    output.innerHTML = '<div class="empty-state"><div class="empty-icon">⚠️</div><p>Error generating plan. Please try again.</p></div>';
    console.error(err);
  });
}

/* ── Superfoods ─────────────────────────────────────────────────── */
function renderSuperfoodChips() {
  const superfoods = [
    { emoji: '🧈', name: 'Turmeric (Haldi)', sub: 'Anti-inflammatory' },
    { emoji: '🟢', name: 'Amla', sub: 'Vitamin C powerhouse' },
    { emoji: '🌿', name: 'Moringa', sub: 'Complete nutrition' },
    { emoji: '🌾', name: 'Fenugreek (Methi)', sub: 'Blood sugar control' },
    { emoji: '🥜', name: 'Flax Seeds', sub: 'Omega-3 fatty acids' },
    { emoji: '🍯', name: 'Ghee', sub: 'Healthy fats (in moderation)' },
    { emoji: '🥛', name: 'Curd/Yogurt', sub: 'Probiotics for gut health' },
    { emoji: '🌱', name: 'Sprouts', sub: 'Protein & enzymes' },
  ];

  const container = document.getElementById('superfoodCards');
  if (!container) return;

  container.innerHTML += superfoods.map(sf => `
    <div class="col-6 col-md-3">
      <div class="superfood-chip">
        <span class="sf-em">${sf.emoji}</span>
        <div>
          <div class="sf-nm">${sf.name}</div>
          <div class="sf-sub">${sf.sub}</div>
        </div>
      </div>
    </div>
  `).join('');
}

function loadSuperfoods() {
  const output = document.getElementById('superfoodsGrid');
  if (!output) return;

  showLoading('Loading AI superfoods guide...');

  fetch('/api/superfoods')
  .then(res => res.json())
  .then(data => {
    hideLoading();
    output.innerHTML = `<div class="superfoods-output">${formatMarkdown(data.superfoods_info)}</div>`;
    showToast('✅ Guide loaded!');
  })
  .catch(err => {
    hideLoading();
    output.innerHTML = '<div class="empty-state"><div class="empty-icon">⚠️</div><p>Error loading guide</p></div>';
    console.error(err);
  });
}

/* ── Loading Overlay ────────────────────────────────────────────── */
function showLoading(text = 'Processing...') {
  const overlay = document.getElementById('loadingOverlay');
  const textEl = document.getElementById('loadingText');
  if (overlay) {
    overlay.classList.remove('d-none');
    if (textEl) textEl.textContent = text;
  }
}

function hideLoading() {
  document.getElementById('loadingOverlay')?.classList.add('d-none');
}

/* ── Toast Notifications ────────────────────────────────────────── */
function showToast(message) {
  const toastBody = document.getElementById('toastBody');
  const toastEl = document.getElementById('appToast');
  if (!toastBody || !toastEl) return;

  toastBody.textContent = message;
  const toast = new bootstrap.Toast(toastEl, { delay: 3000 });
  toast.show();
}

/* ── Health Status Check ────────────────────────────────────────── */
function checkHealth() {
  fetch('/api/health')
  .then(res => res.json())
  .then(data => {
    console.log('NutriAI Health:', data);
  })
  .catch(() => console.warn('Health check failed'));
}

