let currentProfile = {};
let familyMembers = [];
let glassesOfWater = 0;
let chatHistory = [];

/* ── On Page Load ───────────────────────────────────────────────── */
document.addEventListener('DOMContentLoaded', () => {
  initApp();
});

function initApp() {
  // Load persisted data from localStorage
  loadProfile();
  loadFamilyMembers();
  loadWaterTracking();
  loadDarkMode();

  // Set up tab navigation
  setupTabs();

  // Show welcome message in chat
  showWelcomeMessage();

