function saveProfile() {
  currentProfile = {
    name:      document.getElementById('pName')?.value || '',
    age:       parseInt(document.getElementById('pAge')?.value)    || 25,
    weight:    parseFloat(document.getElementById('pWeight')?.value) || 65,
    height:    parseFloat(document.getElementById('pHeight')?.value) || 165,
    gender:    document.getElementById('pGender')?.value    || 'female',
    diet_type: document.getElementById('pDiet')?.value      || 'vegetarian',
    goal:      document.getElementById('pGoal')?.value      || 'maintain health',
    health_condition: document.getElementById('pCondition')?.value || 'none',
  };

  localStorage.setItem('nutriai_profile', JSON.stringify(currentProfile));
  updateDashboardFromProfile();
  showToast('✅ Profile saved!');
}

function loadProfile() {
  const saved = localStorage.getItem('nutriai_profile');
  if (saved) {
    currentProfile = JSON.parse(saved);

    // Populate form fields
    const set = (id, val) => { const el = document.getElementById(id); if (el) el.value = val || ''; };
    set('pName',      currentProfile.name);
    set('pAge',       currentProfile.age);
    set('pWeight',    currentProfile.weight);
    set('pHeight',    currentProfile.height);
    set('pGender',    currentProfile.gender   || 'female');
    set('pDiet',      currentProfile.diet_type|| 'vegetarian');
    set('pGoal',      currentProfile.goal     || 'maintain health');
    set('pCondition', currentProfile.health_condition || 'none');
  }
}

function updateDashboardFromProfile() {
  if (!currentProfile.weight || !currentProfile.height || !currentProfile.age) {
    return;
  }

  // Calculate BMR and TDEE
  const bmr = calculateBMR(
    currentProfile.weight, currentProfile.height,
    currentProfile.age, currentProfile.gender || 'female'
  );
  const tdee = Math.round(bmr * 1.55);
  const protein = Math.round(currentProfile.weight * 1.3);
  const carbs = Math.round((tdee * 0.45) / 4);
  const fat = Math.round((tdee * 0.30) / 9);

  document.getElementById('statCalories').textContent = tdee;
  document.getElementById('statProtein').textContent = `${protein}g`;
  document.getElementById('statCarbs').textContent = `${carbs}g`;
  document.getElementById('statFat').textContent = `${fat}g`;
  document.getElementById('ringCalText').textContent = tdee;

  // Update macro ring arcs (SVG arcs — stroke-dasharray)
  const proteinPct = (protein * 4) / tdee;
  const carbsPct = (carbs * 4) / tdee;
  const fatPct = (fat * 9) / tdee;

  const circumference = 2 * Math.PI * 50;
  document.getElementById('macroProteinArc')?.setAttribute('stroke-dasharray', `${proteinPct * circumference} ${circumference}`);
  document.getElementById('macroCarbsArc')?.setAttribute('stroke-dasharray', `${carbsPct * circumference} ${circumference}`);
  document.getElementById('macroFatArc')?.setAttribute('stroke-dasharray', `${fatPct * circumference} ${circumference}`);
}

function calculateBMR(weight, height, age, gender) {
  if (gender === 'male') {
    return 10 * weight + 6.25 * height - 5 * age + 5;
  } else {
    return 10 * weight + 6.25 * height - 5 * age - 161;
  }
}

